class HashFile:
    def __init__(self, size=100):
        self.size = size
        self.table = [None] * size

    def hash_function(self, key):
        """Simple hash: key mod table size"""
        return key % self.size

    def insert(self, key, record):
        """Insert with linear probing for collision handling"""
        index = self.hash_function(key)
        original_index = index

        while self.table[index] is not None:
            index = (index + 1) % self.size
            if index == original_index:
                raise Exception("Hash table full")

        self.table[index] = record

    def search(self, key):
        """Search using same probing sequence"""
        index = self.hash_function(key)
        original_index = index

        while self.table[index] is not None:
            if self.table[index]['key'] == key:
                return self.table[index]
            index = (index + 1) % self.size
            if index == original_index:
                break

        return None  # Not found

PROCEDURE ISAM_Read(fileName, searchKey)
  // Step 1: Search Primary Index
  primaryIndex ← LOAD(fileName + ".idx1")
  cylinderEntry ← BINARY_SEARCH(primaryIndex, searchKey)

  // Step 2: Get Track Index address
  trackIndexAddr ← cylinderEntry.trackIndexPointer
  trackIndex ← LOAD(trackIndexAddr)

  // Step 3: Search Track Index
  trackEntry ← BINARY_SEARCH(trackIndex, searchKey)

  // Step 4: Read Data Block
  dataBlockAddr ← trackEntry.dataBlockPointer
  dataBlock ← LOAD(dataBlockAddr)

  // Step 5: Search within Block
  record ← LINEAR_SEARCH(dataBlock, searchKey)

  RETURN record
END PROCEDURE
